INSERT INTO systems (code, title, system_type, quick_answer, key_remote, mechanical_key, transponder, programming, making_key, decoders, lock_parts, warnings, status) VALUES ('CHRY-1', 'GEN4 Proximity Remote System', 'Proximity / Smart Key', '["This vehicle uses a GEN4 proximity remote system.", "A key programmer and PIN are required.", "Some 2018+ vehicles may require a gateway bypass cable for proximity remote programming.", "Always verify the exact part number by VIN before ordering."]', '{"remote_type": "Proximity fob", "frequency": "433 MHz", "fcc_id": "M3N-40821302", "known_options": [{"years": "2015-2017", "models": "Chrysler 200", "part": "68155686AB", "buttons": "4", "notes": "Proximity fob"}, {"years": "2015-2017", "models": "Chrysler 200", "part": "68155687AB", "buttons": "5", "notes": "Remote start"}, {"years": "2011-2018", "models": "Chrysler 300 / 300C", "part": "56046758AF or ILCO PRX-CHRY-4B6", "buttons": "4", "notes": "Proximity fob"}, {"years": "2011-2018", "models": "Chrysler 300 / 300C", "part": "56046759AF or ILCO PRX-CHRY-5B5", "buttons": "5", "notes": "Remote start"}, {"years": "2011-2018", "models": "Chrysler 300 / 300C SRT", "part": "68234957AA", "buttons": "5", "notes": "Remote start"}, {"years": "2019-2021", "models": "Chrysler 300 / 300C", "part": "68394190AA", "buttons": "4", "notes": "Proximity fob"}, {"years": "2019-2021", "models": "Chrysler 300 / 300C", "part": "68394191AA", "buttons": "5", "notes": "Remote start"}]}', '{"code_series": "M001-M2618", "style": "Double-sided", "card": "CX102", "ilco_keyway": "Y159 / related CHRY emergency blade", "macs": "2", "start_cut": ".310", "cut_to_cut": ".092", "spacing": {"1": ".941", "2": ".849", "3": ".757", "4": ".665", "5": ".573", "6": ".481", "7": ".389", "8": ".297"}, "depths": {"1": ".340", "2": ".315", "3": ".290", "4": ".265"}, "cutting_setup": {"Curtis clipper": "Use CHRY-5 cam and CHRY-5A carriage.", "Pak-A-Punch": "Use PAK-C5.", "Framon": "Lay the tip-stop clip flat against the left side of the vise and set the first cut at .310."}, "cut_position_map": [{"lock": "Ignition", "positions": [], "note": "No mechanical ignition lock on this system."}, {"lock": "Doors", "positions": [1, 2, 3, 4, 5, 6, 7, 8], "note": "Door lock can be decoded for a working emergency key."}, {"lock": "Trunk", "positions": [1, 2, 3, 4, 5, 6, 7, 8], "note": "Decode if equipped and accessible."}]}', '{"transponder_type": "Proximity", "chip": "Philips 46", "reusable": "No, except some 2011-2018 units may be reusable", "test_key": "Y157 / Y159"}', '{"pin_required": "Yes", "factory_tool": "MicroPod / wiTECH", "cloning": "No cloning for this system.", "tools": [{"name": "Smart Pro", "status": "supported"}, {"name": "TCODE / MVP Pro", "status": "check support"}, {"name": "TDB1000", "status": "check support"}, {"name": "Hotwire", "status": "check support"}, {"name": "Auto Pro Pad", "status": "check support"}, {"name": "Autel IM608", "status": "check support"}]}', '{"code_availability": "No lock codes listed for this system.", "methods": ["Decode the door lock using a compatible lock decoder or reader.", "Use Chrysler tryout keys or a supported tryout set.", "Remove and decode a door or trunk cylinder. Once the required cuts are known, cut the emergency key."], "field_workflow": [{"step": "Confirm the vehicle and system", "detail": "Match year, model, and trim first. For 2018+ vehicles, plan for a security gateway bypass before attempting proximity programming."}, {"step": "Verify the fob by VIN", "detail": "Use the VIN or dealer catalog to confirm the exact proximity fob part number. Do not rely only on button count."}, {"step": "Prepare programming access", "detail": "Have a supported programmer, PIN access, and a bypass cable when required. Confirm support in the programmer application before connecting."}, {"step": "Generate the emergency key", "detail": "Decode the door lock with a reader/decoder, use a supported tryout set, or remove and decode an accessible door/trunk cylinder."}, {"step": "Cut the emergency blade", "detail": "Use the M001-M2618 code series with the spacing/depth values shown below. Confirm the first cut and machine setup before cutting."}, {"step": "Program the proximity fob", "detail": "Use the selected programmer with PIN access. If programming fails on 2018+ vehicles, re-check gateway bypass and vehicle support."}, {"step": "Verify all functions", "detail": "Test lock, unlock, trunk, panic, remote start when present, proximity start, and emergency blade operation before releasing the vehicle."}]}', '[{"tool": "Determinator", "reference": "CHR 2"}, {"tool": "Lishi", "reference": "CY24"}, {"tool": "AccuReader", "reference": "CHRY 8"}, {"tool": "EEZ Reader", "reference": "Y157"}, {"tool": "Cobra", "reference": "KDC8"}]', '[{"years": "2015-2017", "models": "Chrysler 200", "ignition_lock": "Not available from STRATTEC", "door_lock": "Not available from STRATTEC", "trunk_lock": "Not available from STRATTEC", "pin_kit": "703927"}, {"years": "2011-2021", "models": "Chrysler 300 / 300C", "ignition_lock": "Not available from STRATTEC", "door_lock": "Not available from STRATTEC", "trunk_lock": "Not available from STRATTEC", "pin_kit": "703927"}]', '["Verify part numbers by VIN before ordering.", "Confirm key programmer support before connecting to the vehicle.", "Some newer vehicles require gateway bypass access.", "PIN access is required for programming.", "Do not assume a reusable fob unless the specific unit and year range have been confirmed."]', 'approved') ON CONFLICT (code) DO UPDATE SET title = EXCLUDED.title, system_type = EXCLUDED.system_type, quick_answer = EXCLUDED.quick_answer, key_remote = EXCLUDED.key_remote, mechanical_key = EXCLUDED.mechanical_key, transponder = EXCLUDED.transponder, programming = EXCLUDED.programming, making_key = EXCLUDED.making_key, decoders = EXCLUDED.decoders, lock_parts = EXCLUDED.lock_parts, warnings = EXCLUDED.warnings, status = EXCLUDED.status;
